class Solution:
    def searchRange(self, nums, target):
        def lower(x):
            lo, hi = 0, len(nums)
            while lo < hi:
                mid = (lo + hi) // 2
                if nums[mid] < x:
                    lo = mid + 1
                else:
                    hi = mid
            return lo
        left = lower(target)
        if left == len(nums) or nums[left] != target:
            return [-1, -1]
        right = lower(target + 1) - 1
        return [left, right]

