var searchRange = function(nums, target) {
    const lower = (x) => {
        let lo = 0, hi = nums.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (nums[mid] < x) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    };
    const left = lower(target);
    if (left === nums.length || nums[left] !== target) return [-1, -1];
    const right = lower(target + 1) - 1;
    return [left, right];
};
